let AWSGuardDuty_Main = (lookback: timespan = timespan(null)) {
    let config = AWSGuardDuty_Config();
    let _defaultLookback  = totimespan(toscalar(config | where Setting == "DefaultLookback"  | project Value));
    let _maxLookback      = totimespan(toscalar(config | where Setting == "MaxLookback"      | project Value));
    let _lookback = iff(isnull(lookback), _defaultLookback, iff(lookback > _maxLookback, _maxLookback, lookback));
    let _tableName        = toscalar(config | where Setting == "TableName"                   | project Value);
    let _rawColumn        = toscalar(config | where Setting == "RawColumn"                   | project Value);
    let _altRawColumn     = toscalar(config | where Setting == "AlternateRawColumn"          | project Value);
    let _enableValidation = tobool(toscalar(config | where Setting == "EnableDataValidation"    | project Value));
    let _handleEnvelope   = tobool(toscalar(config | where Setting == "HandleEventBridgeEnvelope" | project Value));
    let _minSeverity      = todouble(toscalar(config | where Setting == "MinSeverityScore"    | project Value));
    let _maxSeverity      = todouble(toscalar(config | where Setting == "MaxSeverityScore"    | project Value));
    let _parserVersion    = toscalar(config | where Setting == "ParserVersion"               | project Value);
    table(_tableName)
    | where TimeGenerated >= ago(_lookback)
    | extend RawJson = iff(isnotempty(column_ifexists(_rawColumn, "")), column_ifexists(_rawColumn, ""), column_ifexists(_altRawColumn, ""))
    | where isnotempty(RawJson)
    | extend _raw = try_parse_json(RawJson)
    | where isnotempty(_raw) and _raw != dynamic({})
    | extend gd = iff(_handleEnvelope and tostring(_raw["detail-type"]) == "GuardDuty Finding", _raw.detail, _raw)
    | project-away _raw
    | where isnotempty(gd) and gd != dynamic({})
    | extend SchemaVersion = tostring(gd.schemaVersion)
    | where not(_enableValidation) or (isnotempty(SchemaVersion) and SchemaVersion startswith "2.")
    | extend
        EventTime    = iff(isnotempty(tostring(gd.createdAt)), todatetime(gd.createdAt), TimeGenerated),
        UpdatedTime  = todatetime(gd.updatedAt),
        FindingId    = tostring(gd.id),
        FindingType  = tostring(gd.type),
        Severity     = iff(isnull(todouble(gd.severity)) or todouble(gd.severity) < _minSeverity or todouble(gd.severity) > _maxSeverity, 0.0, todouble(gd.severity)),
        Title        = tostring(gd.title),
        Description  = tostring(gd.description),
        AwsAccountId = tostring(gd.accountId),
        AwsRegion    = tostring(gd.region),
        Partition    = tostring(gd.partition),
        DetectorId   = tostring(gd.service.detectorId),
        ServiceName  = tostring(gd.service.serviceName),
        ResourceType = tostring(gd.resource.resourceType),
        ActionType   = tostring(gd.service.action.actionType)
    | extend DataQualityScore = iff(isnotempty(FindingId), 20, 0) + iff(isnotempty(FindingType), 20, 0) + iff(Severity > 0, 20, 0) + iff(isnotempty(AwsAccountId), 20, 0) + iff(isnotempty(AwsRegion), 20, 0)
    | where not(_enableValidation) or DataQualityScore >= 60
    | extend SeverityLevel = case(Severity >= 8.5, "Critical", Severity >= 7.0, "High", Severity >= 4.0, "Medium", Severity >= 1.0, "Low", Severity > 0, "Informational", "Unknown")
    | extend ParsingTimestamp = now(), ParserVersion = _parserVersion, RecordSource = "AWSGuardDuty_Main"
    | project TimeGenerated, EventTime, UpdatedTime, ParsingTimestamp, FindingId, FindingType, DetectorId, Severity, SeverityLevel, Title, Description, AwsAccountId, AwsRegion, Partition, ServiceName, ResourceType, ActionType, DataQualityScore, SchemaVersion, ParserVersion, RecordSource, RawJson, gd
};
